theme.custom_css_code:
.unibet-ux{
  max-width:1180px;
  margin:0 auto;
  font-family:Arial,sans-serif;
  color:#1f2937;
}
.unibet-ux *,
.unibet-ux *::before,
.unibet-ux *::after{
  box-sizing:border-box;
}
.unibet-ux .ux-grid{
  display:grid;
  grid-template-columns:1fr;
  gap:24px;
}
.unibet-ux .ux-card{
  background:transparent;
  border:1px solid #d9dee7;
  border-radius:20px;
  overflow:hidden;
}
.unibet-ux .ux-scroll{
  overflow-x:auto;
  -webkit-overflow-scrolling:touch;
}
.unibet-ux table{
  width:100%;
  min-width:720px;
  border-collapse:collapse;
  font-size:14px;
}
.unibet-ux td{
  padding:14px 16px;
  border-bottom:1px solid #e5e7eb;
  vertical-align:top;
}
.unibet-ux tr:last-child td{
  border-bottom:none;
}
.unibet-ux td:first-child{
  width:32%;
  font-weight:700;
  color:#111827;
  background:#f8fafc;
}
.unibet-ux td:last-child{
  color:#374151;
}
.unibet-ux .tiles{
  display:grid;
  grid-template-columns:repeat(4,1fr);
  gap:16px;
  padding:18px;
}
.unibet-ux .tile{
  position:relative;
  min-height:168px;
  border:1px solid #e5e7eb;
  border-radius:18px;
  background:linear-gradient(180deg,#ffffff 0%,#f8fafc 100%);
  padding:16px;
  overflow:hidden;
}
.unibet-ux .tile::before{
  content:"";
  position:absolute;
  right:-24px;
  top:-24px;
  width:96px;
  height:96px;
  border-radius:50%;
  background:rgba(16,24,40,0.05);
}
.unibet-ux .tile-label{
  position:relative;
  z-index:1;
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:10px;
  margin-bottom:14px;
  font-size:15px;
  font-weight:700;
  color:#111827;
}
.unibet-ux .tile-note{
  position:relative;
  z-index:1;
  font-size:13px;
  line-height:1.45;
  color:#4b5563;
}
.unibet-ux .slot-reels,
.unibet-ux .live-graphic,
.unibet-ux .table-graphic,
.unibet-ux .new-graphic{
  position:relative;
  z-index:1;
  display:flex;
  gap:8px;
  margin-bottom:14px;
}
.unibet-ux .reel{
  flex:1;
  height:64px;
  border:1px solid #dbe1ea;
  border-radius:14px;
  background:#fff;
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:24px;
}
.unibet-ux .live-chip{
  flex:1;
  height:64px;
  border-radius:16px;
  background:linear-gradient(135deg,#111827 0%,#374151 100%);
  color:#fff;
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:22px;
}
.unibet-ux .table-stack{
  flex:1;
  height:64px;
  border-radius:16px;
  border:1px solid #dbe1ea;
  background:
    linear-gradient(180deg,#ffffff 0%,#f9fafb 100%);
  display:flex;
  align-items:flex-end;
  justify-content:center;
  gap:6px;
  padding:10px;
}
.unibet-ux .table-stack span{
  width:18%;
  border-radius:8px 8px 4px 4px;
  background:#1f2937;
  opacity:.92;
}
.unibet-ux .table-stack span:nth-child(1){height:36%;}
.unibet-ux .table-stack span:nth-child(2){height:58%;}
.unibet-ux .table-stack span:nth-child(3){height:78%;}
.unibet-ux .table-stack span:nth-child(4){height:52%;}
.unibet-ux .new-badge{
  flex:1;
  height:64px;
  border-radius:16px;
  border:1px dashed #cdd5df;
  display:flex;
  align-items:center;
  justify-content:center;
  font-size:14px;
  font-weight:700;
  color:#111827;
  background:#fff;
}
.unibet-ux .chart{
  padding:20px 18px 18px;
  display:grid;
  gap:14px;
}
.unibet-ux .metric{
  display:grid;
  grid-template-columns:160px 1fr 52px;
  gap:14px;
  align-items:center;
}
.unibet-ux .metric-name{
  font-size:14px;
  font-weight:700;
  color:#111827;
}
.unibet-ux .metric-bar{
  height:14px;
  border-radius:999px;
  background:#eef2f7;
  overflow:hidden;
  position:relative;
}
.unibet-ux .metric-fill{
  height:100%;
  border-radius:999px;
  background:linear-gradient(90deg,#111827 0%,#4b5563 100%);
}
.unibet-ux .metric-value{
  text-align:right;
  font-size:13px;
  font-weight:700;
  color:#374151;
}
@media (max-width:980px){
  .unibet-ux .tiles{
    grid-template-columns:repeat(2,1fr);
  }
}
@media (max-width:640px){
  .unibet-ux .tiles{
    grid-template-columns:1fr;
  }
  .unibet-ux .metric{
    grid-template-columns:1fr;
    gap:8px;
  }
  .unibet-ux .metric-value{
    text-align:left;
  }
}
